import{_ as a,c as n,a as t,o as e}from"./app-CEcM0piI.js";const p={};function l(i,s){return e(),n("div",null,s[0]||(s[0]=[t(`<p>逻辑移位运算的对象是无符号数 左移：高位移除，低位补0 右移：低位移除，高位补0 ![[Clip_2024-03-31_11-39-37.png]] 先创建一个8位无符号变量，最低位b0的初始值为1，其他位的初始值为0，然后把该变量逻辑左移六位，再按位取反，得到101111，再与寄存器中的内容按位与运算就可以只清零b6位而不影响其他位 若想要改为b6位置1操作，可以左移6位（010000）后对寄存器的内容按位或操作 ![[Clip_2024-03-31_11-46-29.png]]</p><h1 id="算术移位运算" tabindex="-1"><a class="header-anchor" href="#算术移位运算"><span>算术移位运算</span></a></h1><p>算术移位运算的对象是有符号数(针对定点数，包括定点整数和定点小数) 不论正数还是负数，<strong>符号位保持不变，仅对数值位进行移位(左移或右移)</strong> 对真值的原码、反码和补码进行算术移位后，它们各自所对应的新的真值应该保持一致。 当真值为正数时，真值的原码、反码和补码都相同，因此，对它们进行算术移位后，它们各自所对应的新的真值自然是保持一致的。对于移位后出现的空位，规定添补0。 当真值为负数时，真值的原码、反码和补码都不同，因此，对它们进行算术移位后为了确保它们各自所对应的新的真值保持一致，对于移位后出现的空位，添补规则各不相同， ![[Clip_2024-03-31_12-01-47.png]] 在未出现因丢位产生结果出错或精度缺失的情况下： n为位移次数 左移：乘以<span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><msup><mn>2</mn><mi>n</mi></msup></mrow><annotation encoding="application/x-tex">2^n</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.6644em;"></span><span class="mord"><span class="mord">2</span><span class="msupsub"><span class="vlist-t"><span class="vlist-r"><span class="vlist" style="height:0.6644em;"><span style="top:-3.063em;margin-right:0.05em;"><span class="pstrut" style="height:2.7em;"></span><span class="sizing reset-size6 size3 mtight"><span class="mord mathnormal mtight">n</span></span></span></span></span></span></span></span></span></span></span> 右移：除以<span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><msup><mn>2</mn><mi>n</mi></msup></mrow><annotation encoding="application/x-tex">2^n</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.6644em;"></span><span class="mord"><span class="mord">2</span><span class="msupsub"><span class="vlist-t"><span class="vlist-r"><span class="vlist" style="height:0.6644em;"><span style="top:-3.063em;margin-right:0.05em;"><span class="pstrut" style="height:2.7em;"></span><span class="sizing reset-size6 size3 mtight"><span class="mord mathnormal mtight">n</span></span></span></span></span></span></span></span></span></span></span></p><p><strong>对于有符号定点数的补码另一种以为方法</strong> 符号位也参与移位 左移：高位移除，低位补0，移动前后若符号位发生变化，则发生溢出 右移：低位移除，高位添补符号</p><p>优点： 左移时，有检测出发生溢出的方法：符号位发生变化可判定溢出 符号位与数值位一起移位，方便ALU处理</p><p><strong>C语言中的移位运算</strong> 左移运算对应汇编指令中的逻辑左移，即高位移除，低位补0 右移运算根据操作数是无符号数还是有符号数分别对应汇编指令中的逻辑右移和算数右移 逻辑右移：将低位移除，高位补0 算数右移：低位移除，高位补原数据的符号位</p><h1 id="循环移位" tabindex="-1"><a class="header-anchor" href="#循环移位"><span>循环移位</span></a></h1><p>循环移位的对象是无符号数</p><p>将无符号数二进制形式中的各个位向左或向右移动，被移出的位会重新出现在另一端，形成循环在很多处理器架构中，循环移位指令会影响状态寄存器中的进位标志CF（Carry Flag）位，CF标志位用于标识在执行算术或逻辑操作时是否发生了进位。</p><p>根据CF标志位是否加入循环移位过程，循环移位可分为以下四种: 不带CF标志位的循环移位称为小循环</p><ol><li>不带CF标志位的循环右移</li><li>不带CF标志位的循环左移 带CF标志位的循环移位称为大循环</li><li>带CF标志位的循环右移</li><li>带CF标志位的循环左移 不管带不带CF标志位CF标志位都是存在的，在不带CF标志位的循环移位中，CF标志位存储被移出的数 ![[Clip_2024-03-31_12-27-39.png]] 带CF标志位的循环移位中，CF标志位本身也存储有一个数据也参与移位运算，就相当于多了一个位 ![[Clip_2024-03-31_12-27-56.png]]</li></ol><p><strong>循环移位的应用</strong> 加密算法、哈希函数、优化算法</p><ul><li>加密算法： 通过循环移位可以实现数据的混淆和置换，增强加密算法的安全性</li><li>哈希函数： 通过循环移位可以用来改变输入数据的排列顺序，以产生不同的哈希值，有利于增强哈希函数的混淆性和扩散性。</li><li>优化算法： 在某些算法中，循环移位可以用于优化性能和节省资源。例如，在图形处理和数字信号处理中，循环移位可以用于加速算法的执行。</li></ul><p><strong>循环移位的C语言实现</strong> C语言中并没有直接提供循环移位操作符 通常情况下，可以使用移位运算操作符（例如:左移“&lt;&lt;”或右移“&gt;&gt;”）和位运算操作符（例如:或运算“|”）来实现。</p><div class="language- line-numbers-mode has-collapsed-lines collapsed" data-highlighter="shiki" data-ext="" style="--vp-collapsed-lines:15;--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>#include &lt;stdio.h&gt;</span></span>
<span class="line"><span>//循环左移</span></span>
<span class="line"><span>unsigned int circularLeftShift(unsigned int value, int n){</span></span>
<span class="line"><span>	return(value&lt;&lt;n)|(value&gt;&gt;(32-n));</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span>//循环右移</span></span>
<span class="line"><span>unsigned int circularRightShift(unsigned int value, int n){</span></span>
<span class="line"><span>	return(value &gt;&gt;n)|(value&lt;&lt;(32-n));</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>int main(){</span></span>
<span class="line"><span>	unsigned int usi= 0x12345678;//待循环移位的32位无符号整数</span></span>
<span class="line"><span>	int d = 4;//移位距离(即一次循环移动几位)</span></span>
<span class="line"><span>	printf(&quot;0riginal value: 0x%x\\n&quot;, usi);</span></span>
<span class="line"><span>	printf(&quot;Circular left shift by %d bits:0x%x\\n&quot;,d,circularLeftShift(usi, d));</span></span>
<span class="line"><span>	printf(&quot;Circular right shift by %d bits:0x%x\\n&quot;,d,circularRightShift(usi, d));</span></span>
<span class="line"><span>	return 0;</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div><div class="collapsed-lines"></div></div><h1 id="定点数的加法和减法运算" tabindex="-1"><a class="header-anchor" href="#定点数的加法和减法运算"><span>定点数的加法和减法运算</span></a></h1><h2 id="补码加减法运算公式" tabindex="-1"><a class="header-anchor" href="#补码加减法运算公式"><span>补码加减法运算公式</span></a></h2><p>[[计算机组成原理/attachment/3b6d4b37cb29fe0c904fdcf753b5d9c3_MD5.jpeg|Open: Clip_2024-05-10_14-07-02.png]] ![[计算机组成原理/attachment/3b6d4b37cb29fe0c904fdcf753b5d9c3_MD5.jpeg]]</p><h3 id="补码加减法溢出检测" tabindex="-1"><a class="header-anchor" href="#补码加减法溢出检测"><span>补码加减法溢出检测</span></a></h3><p>计算机的字长是有限的，因此所能表示的数据范围也是有限的。 当运算结果超出所能表示的数据范围时，就会出现溢出(Overflow）。 溢出会导致错误的运算结果。 计算机系统设计人员必须要解决溢出的检测问题，以便在发生溢出时计算机能做出相应的处理。</p><h4 id="根据操作数的符号位与运算结果的符号位是否一致进行判断" tabindex="-1"><a class="header-anchor" href="#根据操作数的符号位与运算结果的符号位是否一致进行判断"><span>根据操作数的符号位与运算结果的符号位是否一致进行判断</span></a></h4><p>[[计算机组成原理/attachment/95c5089587c3c89ac25f264c7d498316_MD5.jpeg|Open: Clip_2024-05-10_14-20-46.png]] ![[计算机组成原理/attachment/95c5089587c3c89ac25f264c7d498316_MD5.jpeg]]</p><p>[[计算机组成原理/attachment/07f894756d9573d67fe21c9b36b3c1ac_MD5.jpeg|Open: Clip_2024-05-10_14-20-58.png]] ![[计算机组成原理/attachment/07f894756d9573d67fe21c9b36b3c1ac_MD5.jpeg]]</p><p>[[计算机组成原理/attachment/9213d2daa6bfc18a239db1c1cf4d9c1d_MD5.jpeg|Open: Clip_2024-05-10_18-22-32.png]] ![[计算机组成原理/attachment/9213d2daa6bfc18a239db1c1cf4d9c1d_MD5.jpeg]] [[计算机组成原理/attachment/86e7f0509ca3b61e94a376f5fee403e5_MD5.jpeg|Open: Clip_2024-05-10_18-27-19.png]] ![[计算机组成原理/attachment/86e7f0509ca3b61e94a376f5fee403e5_MD5.jpeg]]</p><h4 id="根据运算过程中最高数值位的进位和符号位的进位是否一致进行判断" tabindex="-1"><a class="header-anchor" href="#根据运算过程中最高数值位的进位和符号位的进位是否一致进行判断"><span>根据运算过程中最高数值位的进位和符号位的进位是否一致进行判断</span></a></h4><p>不同可判定为产生溢出，相同可判定为没有产生溢出 [[计算机组成原理/attachment/d5b25b6f61837c8960b84a53d183aec6_MD5.jpeg|Open: Clip_2024-05-10_18-35-24.png]] ![[计算机组成原理/attachment/d5b25b6f61837c8960b84a53d183aec6_MD5.jpeg]]</p><p>最高数值位的进位记为<span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><msub><mi>C</mi><mrow><mi>n</mi><mo>−</mo><mn>1</mn></mrow></msub></mrow><annotation encoding="application/x-tex">C_{n-1}</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.8917em;vertical-align:-0.2083em;"></span><span class="mord"><span class="mord mathnormal" style="margin-right:0.07153em;">C</span><span class="msupsub"><span class="vlist-t vlist-t2"><span class="vlist-r"><span class="vlist" style="height:0.3011em;"><span style="top:-2.55em;margin-left:-0.0715em;margin-right:0.05em;"><span class="pstrut" style="height:2.7em;"></span><span class="sizing reset-size6 size3 mtight"><span class="mord mtight"><span class="mord mathnormal mtight">n</span><span class="mbin mtight">−</span><span class="mord mtight">1</span></span></span></span></span><span class="vlist-s">​</span></span><span class="vlist-r"><span class="vlist" style="height:0.2083em;"><span></span></span></span></span></span></span></span></span></span>符号位的进位记为<span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><msub><mi>C</mi><mi>n</mi></msub></mrow><annotation encoding="application/x-tex">C_n</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.8333em;vertical-align:-0.15em;"></span><span class="mord"><span class="mord mathnormal" style="margin-right:0.07153em;">C</span><span class="msupsub"><span class="vlist-t vlist-t2"><span class="vlist-r"><span class="vlist" style="height:0.1514em;"><span style="top:-2.55em;margin-left:-0.0715em;margin-right:0.05em;"><span class="pstrut" style="height:2.7em;"></span><span class="sizing reset-size6 size3 mtight"><span class="mord mathnormal mtight">n</span></span></span></span><span class="vlist-s">​</span></span><span class="vlist-r"><span class="vlist" style="height:0.15em;"><span></span></span></span></span></span></span></span></span></span> 溢出标志位记为OF，当OF为1时表示发生溢出；Cn-1与 Cn不同，则产生溢出（即OF为1）：<span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mi>O</mi><mi>F</mi><mo>=</mo><msub><mi>C</mi><mrow><mi>n</mi><mo>−</mo><mn>1</mn></mrow></msub><mo>⊕</mo><msub><mi>C</mi><mi>n</mi></msub></mrow><annotation encoding="application/x-tex">OF = C_{n-1}\\oplus C_n</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:0.6833em;"></span><span class="mord mathnormal" style="margin-right:0.13889em;">OF</span><span class="mspace" style="margin-right:0.2778em;"></span><span class="mrel">=</span><span class="mspace" style="margin-right:0.2778em;"></span></span><span class="base"><span class="strut" style="height:0.8917em;vertical-align:-0.2083em;"></span><span class="mord"><span class="mord mathnormal" style="margin-right:0.07153em;">C</span><span class="msupsub"><span class="vlist-t vlist-t2"><span class="vlist-r"><span class="vlist" style="height:0.3011em;"><span style="top:-2.55em;margin-left:-0.0715em;margin-right:0.05em;"><span class="pstrut" style="height:2.7em;"></span><span class="sizing reset-size6 size3 mtight"><span class="mord mtight"><span class="mord mathnormal mtight">n</span><span class="mbin mtight">−</span><span class="mord mtight">1</span></span></span></span></span><span class="vlist-s">​</span></span><span class="vlist-r"><span class="vlist" style="height:0.2083em;"><span></span></span></span></span></span></span><span class="mspace" style="margin-right:0.2222em;"></span><span class="mbin">⊕</span><span class="mspace" style="margin-right:0.2222em;"></span></span><span class="base"><span class="strut" style="height:0.8333em;vertical-align:-0.15em;"></span><span class="mord"><span class="mord mathnormal" style="margin-right:0.07153em;">C</span><span class="msupsub"><span class="vlist-t vlist-t2"><span class="vlist-r"><span class="vlist" style="height:0.1514em;"><span style="top:-2.55em;margin-left:-0.0715em;margin-right:0.05em;"><span class="pstrut" style="height:2.7em;"></span><span class="sizing reset-size6 size3 mtight"><span class="mord mathnormal mtight">n</span></span></span></span><span class="vlist-s">​</span></span><span class="vlist-r"><span class="vlist" style="height:0.15em;"><span></span></span></span></span></span></span></span></span></span></p><h4 id="利用变形补码-具有2位符号位的补码-的符号位进行判断" tabindex="-1"><a class="header-anchor" href="#利用变形补码-具有2位符号位的补码-的符号位进行判断"><span>利用变形补码（具有2位符号位的补码）的符号位进行判断</span></a></h4><p>变形补码也称为双符号补码，具有2个符号位，其余与补码相同</p><ul><li>双符号位为00时，表示正数</li><li>双符号位为11时，表示负数</li><li>双符号位为01时，表示正溢出</li><li>双符号位为10时，表示负溢出 溢出判断非常直观，适合手工运算时的溢出检测，但其硬件成本高，需要额外准备机器字长存储双符号位，在计算机中主要采用单符号溢出检测方案。</li></ul><blockquote><p>[!warning] Title 负数变形补码转换成原码仍可以使用反码法或扫描法。</p></blockquote><p>[[计算机组成原理/attachment/5cca2284aeefb9499040e37e15db03fa_MD5.jpeg|Open: Clip_2024-05-10_18-48-05.png]] ![[计算机组成原理/attachment/5cca2284aeefb9499040e37e15db03fa_MD5.jpeg]]</p><h2 id="定点数的加减法运算" tabindex="-1"><a class="header-anchor" href="#定点数的加减法运算"><span>定点数的加减法运算</span></a></h2><h3 id="全加器的硬件逻辑实现" tabindex="-1"><a class="header-anchor" href="#全加器的硬件逻辑实现"><span>全加器的硬件逻辑实现</span></a></h3><p>[[计算机组成原理/attachment/234645b8c9ab3d35247efc015bb115ea_MD5.jpeg|Open: Clip_2024-05-10_21-49-20.png]] ![[计算机组成原理/attachment/234645b8c9ab3d35247efc015bb115ea_MD5.jpeg]] [[计算机组成原理/attachment/cfa81ec27dc7e961c6b7bf240fa9b29a_MD5.jpeg|Open: Clip_2024-05-10_21-48-12.png]] ![[计算机组成原理/attachment/cfa81ec27dc7e961c6b7bf240fa9b29a_MD5.jpeg]]</p><p>[[计算机组成原理/attachment/07bfd31a022c1509ed720ba9221b5eb7_MD5.jpeg|Open: Clip_2024-05-10_21-51-06.png]] ![[计算机组成原理/attachment/07bfd31a022c1509ed720ba9221b5eb7_MD5.jpeg]] [[计算机组成原理/attachment/7d58e485e41ac77acfa42385131f321a_MD5.jpeg|Open: Clip_2024-05-10_21-52-16.png]] ![[计算机组成原理/attachment/7d58e485e41ac77acfa42385131f321a_MD5.jpeg]] [[计算机组成原理/attachment/fcb9b84ab6cbad5a6dd525529db7cac7_MD5.jpeg|Open: Clip_2024-05-10_21-54-39.png]] ![[计算机组成原理/attachment/fcb9b84ab6cbad5a6dd525529db7cac7_MD5.jpeg]]</p><h3 id="串行进位加法器" tabindex="-1"><a class="header-anchor" href="#串行进位加法器"><span>串行进位加法器</span></a></h3><p>也叫行波进位加法器 可以使用n个全加器FA通过进位串联得到n位串行进位加法器 [[计算机组成原理/attachment/3dc35e14f43e6fffef59a9fc3d6ba9a0_MD5.jpeg|Open: Clip_2024-05-11_10-56-04.png]] ![[计算机组成原理/attachment/3dc35e14f43e6fffef59a9fc3d6ba9a0_MD5.jpeg]] 为了让n位串行进位加法器具有溢出检测功能，需要添加一个异或门将最高数值位的进位信号连接到异或门的一个输入端，将符号位的输出信号连接到异或门的另一个输入端，这样就可以使用<strong>最高数值位的进位与符号位的进位是否一致</strong>进行判断，异或门的输出就是检测结果</p><p>如果要是串行进位加法器能够实现补码的减法 根据<span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML"><semantics><mrow><mo stretchy="false">[</mo><mi>x</mi><msub><mo stretchy="false">]</mo><mtext>补</mtext></msub><mo>−</mo><mo stretchy="false">[</mo><mi>y</mi><msub><mo stretchy="false">]</mo><mtext>补</mtext></msub><mo>=</mo><mo stretchy="false">[</mo><mi>x</mi><msub><mo stretchy="false">]</mo><mtext>补</mtext></msub><mo>+</mo><mo stretchy="false">[</mo><mo>−</mo><mi>y</mi><msub><mo stretchy="false">]</mo><mtext>补</mtext></msub></mrow><annotation encoding="application/x-tex">[x]_补-[y]_补=[x]_补+[-y]_补</annotation></semantics></math></span><span class="katex-html" aria-hidden="true"><span class="base"><span class="strut" style="height:1em;vertical-align:-0.25em;"></span><span class="mopen">[</span><span class="mord mathnormal">x</span><span class="mclose"><span class="mclose">]</span><span class="msupsub"><span class="vlist-t vlist-t2"><span class="vlist-r"><span class="vlist" style="height:0.3283em;"><span style="top:-2.55em;margin-left:0em;margin-right:0.05em;"><span class="pstrut" style="height:2.7em;"></span><span class="sizing reset-size6 size3 mtight"><span class="mord cjk_fallback mtight">补</span></span></span></span><span class="vlist-s">​</span></span><span class="vlist-r"><span class="vlist" style="height:0.15em;"><span></span></span></span></span></span></span><span class="mspace" style="margin-right:0.2222em;"></span><span class="mbin">−</span><span class="mspace" style="margin-right:0.2222em;"></span></span><span class="base"><span class="strut" style="height:1em;vertical-align:-0.25em;"></span><span class="mopen">[</span><span class="mord mathnormal" style="margin-right:0.03588em;">y</span><span class="mclose"><span class="mclose">]</span><span class="msupsub"><span class="vlist-t vlist-t2"><span class="vlist-r"><span class="vlist" style="height:0.3283em;"><span style="top:-2.55em;margin-left:0em;margin-right:0.05em;"><span class="pstrut" style="height:2.7em;"></span><span class="sizing reset-size6 size3 mtight"><span class="mord cjk_fallback mtight">补</span></span></span></span><span class="vlist-s">​</span></span><span class="vlist-r"><span class="vlist" style="height:0.15em;"><span></span></span></span></span></span></span><span class="mspace" style="margin-right:0.2778em;"></span><span class="mrel">=</span><span class="mspace" style="margin-right:0.2778em;"></span></span><span class="base"><span class="strut" style="height:1em;vertical-align:-0.25em;"></span><span class="mopen">[</span><span class="mord mathnormal">x</span><span class="mclose"><span class="mclose">]</span><span class="msupsub"><span class="vlist-t vlist-t2"><span class="vlist-r"><span class="vlist" style="height:0.3283em;"><span style="top:-2.55em;margin-left:0em;margin-right:0.05em;"><span class="pstrut" style="height:2.7em;"></span><span class="sizing reset-size6 size3 mtight"><span class="mord cjk_fallback mtight">补</span></span></span></span><span class="vlist-s">​</span></span><span class="vlist-r"><span class="vlist" style="height:0.15em;"><span></span></span></span></span></span></span><span class="mspace" style="margin-right:0.2222em;"></span><span class="mbin">+</span><span class="mspace" style="margin-right:0.2222em;"></span></span><span class="base"><span class="strut" style="height:1em;vertical-align:-0.25em;"></span><span class="mopen">[</span><span class="mord">−</span><span class="mord mathnormal" style="margin-right:0.03588em;">y</span><span class="mclose"><span class="mclose">]</span><span class="msupsub"><span class="vlist-t vlist-t2"><span class="vlist-r"><span class="vlist" style="height:0.3283em;"><span style="top:-2.55em;margin-left:0em;margin-right:0.05em;"><span class="pstrut" style="height:2.7em;"></span><span class="sizing reset-size6 size3 mtight"><span class="mord cjk_fallback mtight">补</span></span></span></span><span class="vlist-s">​</span></span><span class="vlist-r"><span class="vlist" style="height:0.15em;"><span></span></span></span></span></span></span></span></span></span> 可以将异或门的输出端连接到y端上，异或门的一个输入即为原来的y端，另一个输入端和其他位上的异或门连到一条线上（称为sub端），当sub输入为1时各位上输出到全加器上的结果就是对y端的取反，当sub端输入为0时各位上输出到全加器上的结果就是y端原本的数据。再将sub端连接到FA0，也就是末位的加法器的C0端时当sub输入为1时就可以实现对y端输入的按位取反再加1，由此将y转为-y的补码进行加法运算。当sub端输入为0时没有取反也没有加1因此也不影响加法器的加法运算 [[计算机组成原理/attachment/45ab25f0af61cb649d25e4193689af12_MD5.jpeg|Open: Clip_2024-05-11_11-05-13.png]] ![[计算机组成原理/attachment/45ab25f0af61cb649d25e4193689af12_MD5.jpeg]] <strong>性能</strong> 由于每个高位的一位全加器的运算依赖于其相邻低位的一位全加器的进位输出，因此，所有一位全加器不能并行运算，其时间关键延迟，也就是输出所有本位和所需的时间(2n+4)T，这与串行进位加法器的位数n成线性关系。</p><h3 id="先行进位加法器" tabindex="-1"><a class="header-anchor" href="#先行进位加法器"><span>先行进位加法器</span></a></h3><p>[[计算机组成原理/attachment/ebfc3ca67b4bc7eb9f80a841349208a6_MD5.jpeg|Open: Clip_2024-05-11_11-37-49.png]] yin ![[计算机组成原理/attachment/ebfc3ca67b4bc7eb9f80a841349208a6_MD5.jpeg]]</p><p>因此先行进位电路通常采用四位一组 四位快速加法器 [[计算机组成原理/attachment/31c5139e86656fe313bfd37771e68337_MD5.jpeg|Open: Clip_2024-05-11_11-43-24.png]] ![[计算机组成原理/attachment/31c5139e86656fe313bfd37771e68337_MD5.jpeg]] 四位一组，组内并行进位、组间串行进位的16位加法器 [[计算机组成原理/attachment/6552d557005e9a3751722e255abc9334_MD5.jpeg|Open: Clip_2024-05-11_11-47-46.png]] ![[计算机组成原理/attachment/6552d557005e9a3751722e255abc9334_MD5.jpeg]]</p><p>[[计算机组成原理/attachment/eb7dc4c08ed28e28da6adfeaf37bcbe5_MD5.jpeg|Open: Clip_2024-05-11_11-52-13.png]] ![[计算机组成原理/attachment/eb7dc4c08ed28e28da6adfeaf37bcbe5_MD5.jpeg]] [[计算机组成原理/attachment/fab31fe407dfbb5c825b956aa92bec59_MD5.jpeg|Open: Clip_2024-05-11_11-53-56.png]] ![[计算机组成原理/attachment/fab31fe407dfbb5c825b956aa92bec59_MD5.jpeg]] [[计算机组成原理/attachment/74ae197d61835e9342cd92b0bd49191d_MD5.jpeg|Open: Clip_2024-05-11_11-57-40.png]] ![[计算机组成原理/attachment/74ae197d61835e9342cd92b0bd49191d_MD5.jpeg]]</p><h2 id="无符号数乘法" tabindex="-1"><a class="header-anchor" href="#无符号数乘法"><span>无符号数乘法</span></a></h2><p>乘法运算可以由移位运算和加法运算配合完成 [[计算机组成原理/attachment/2c6a167a5703534d1b03af40a4d97bf2_MD5.jpeg|Open: Clip_2024-05-11_12-27-55.png]] ![[计算机组成原理/attachment/2c6a167a5703534d1b03af40a4d97bf2_MD5.jpeg]] 针对以上问题对笔算乘法进行改进 [[计算机组成原理/attachment/b1dd9230b2e3a18c2395e2108c21086c_MD5.jpeg|Open: Clip_2024-05-11_12-31-08.png]] ![[计算机组成原理/attachment/b1dd9230b2e3a18c2395e2108c21086c_MD5.jpeg]] [[计算机组成原理/attachment/337fb41f42f6bdfb6d2bf856092d9002_MD5.jpeg|Open: Clip_2024-05-11_12-32-13.png]] ![[计算机组成原理/attachment/337fb41f42f6bdfb6d2bf856092d9002_MD5.jpeg]] 需要一个位宽为4位的寄存器存放被乘数x；还需要两个位宽为4位的寄存器分别存放部分积和最终乘积的高位和低位，初始阶段高位寄存器被清！，低位寄存器存放乘数y。再配上加法器及其他相应电路，即可实现乘法运算。 ![[Clip_2024-05-11_12-39-56.png]]</p><h2 id="定点数的原码乘法运算" tabindex="-1"><a class="header-anchor" href="#定点数的原码乘法运算"><span>定点数的原码乘法运算</span></a></h2><p>由于原码表示与无符号数非常类似，仅比无符号数多一个符号，而乘积的符号可以通过参与运算的两个数各自符号的<mark>逻辑异或</mark>求得，因此，上述无符号数乘法运算的硬件逻辑实现，可用于原码一位乘法仅需添加符号位处理即可。 一位乘法：并不是指参与乘法运算的两个操作数都是一位的，而是指在乘法运算过程中，每次根据乘数中的一位来计算位积 [[计算机组成原理/attachment/95987ccfcb4760233076da2ef2fb8f3c_MD5.jpeg|Open: Clip_2024-05-11_14-44-51.png]] ![[计算机组成原理/attachment/95987ccfcb4760233076da2ef2fb8f3c_MD5.jpeg]] 这样符号位进行异或计算后得到运算结果的符号位，与原码分离而二者数据位部分可以直接当作无符号定点小数进行计算</p><h2 id="定点数的补码定点运算" tabindex="-1"><a class="header-anchor" href="#定点数的补码定点运算"><span>定点数的补码定点运算</span></a></h2><p>由于计算机中采用补码表示数据，如果用原码乘法计算两个数的乘积，则运算前需要将补码转换为原码、运算后还需要将原码再转换为补码，这样会增加许多操作步骤。为了减少处理环节，英国的布斯（Booth）夫妇于1950年提出了一种补码乘法，又称为Booth算法 [[计算机组成原理/attachment/385e65096137acf7b4c03824d81cee83_MD5.jpeg|Open: Clip_2024-05-11_20-37-02.png]] ![[计算机组成原理/attachment/385e65096137acf7b4c03824d81cee83_MD5.jpeg]] [[计算机组成原理/attachment/edfa4517e4ed1187cdffc4423f42520a_MD5.jpeg|Open: Clip_2024-05-11_20-42-32.png]] ![[计算机组成原理/attachment/edfa4517e4ed1187cdffc4423f42520a_MD5.jpeg]] ![[Clip_2024-05-11_20-43-46.png]] ![[Clip_2024-05-11_20-49-18.png]] ![[Clip_2024-05-16_10-46-30.png]] ![[Clip_2024-05-16_13-19-33.png]]</p>`,49)]))}const m=a(p,[["render",l]]),h=JSON.parse('{"path":"/base/co/3/","title":"3、移位运算","lang":"zh-CN","frontmatter":{"title":"3、移位运算","createTime":"2025/06/18 20:43:40","permalink":"/base/co/3/"},"readingTime":{"minutes":11.3,"words":3389},"git":{"createdTime":1750599657000,"updatedTime":1750644294000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":2,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/基础/计算机组成原理/3、移位运算.md","headers":[]}');export{m as comp,h as data};
